import axios from 'axios';

const API_BASE_URL = 'http://localhost:3000/api';

// Create axios instance for subjects
const subjectAPI = axios.create({
    baseURL: `${API_BASE_URL}/subjects`,
    headers: {
        'Content-Type': 'application/json',
    },
});

// Add request interceptor to include auth token
subjectAPI.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }
        return config;
    },
    (error) => {
        return Promise.reject(error);
    }
);

// Add response interceptor for better error handling
subjectAPI.interceptors.response.use(
    (response) => response,
    (error) => {
        console.error('API Error:', error.response || error);
        return Promise.reject(error);
    }
);

// Get all subjects with optional filters
export const getAllSubjects = async (filters = {}) => {
    try {
        const params = new URLSearchParams();
        if (filters.category) params.append('category', filters.category);
        if (filters.difficulty) params.append('difficulty', filters.difficulty);
        if (filters.featured) params.append('featured', filters.featured);

        const queryString = params.toString();
        const url = queryString ? `/?${queryString}` : '/';
        const response = await subjectAPI.get(url);
        return response.data;
    } catch (error) {
        console.error('Error fetching subjects:', error);
        throw error;
    }
};

// Get featured subjects
export const getFeaturedSubjects = async () => {
    try {
        const response = await subjectAPI.get('/featured');
        return response.data;
    } catch (error) {
        console.error('Error fetching featured subjects:', error);
        throw error;
    }
};

// Get subjects by category
export const getSubjectsByCategory = async (category) => {
    try {
        const response = await subjectAPI.get(`/category/${encodeURIComponent(category)}`);
        return response.data;
    } catch (error) {
        console.error('Error fetching subjects by category:', error);
        throw error;
    }
};

// Get subject by ID
export const getSubjectById = async (id) => {
    try {
        const response = await subjectAPI.get(`/${id}`);
        return response.data;
    } catch (error) {
        console.error('Error fetching subject:', error);
        throw error;
    }
};

// Search subjects
export const searchSubjects = async (query, filters = {}) => {
    try {
        const params = new URLSearchParams();
        if (query) params.append('q', query);
        if (filters.category) params.append('category', filters.category);
        if (filters.difficulty) params.append('difficulty', filters.difficulty);

        const response = await subjectAPI.get(`/search?${params.toString()}`);
        return response.data;
    } catch (error) {
        console.error('Error searching subjects:', error);
        throw error;
    }
};

// Create new subject (requires authentication)
export const createSubject = async (subjectData) => {
    try {
        console.log('Creating subject with data:', subjectData);
        const response = await subjectAPI.post('/', subjectData);
        return response.data;
    } catch (error) {
        console.error('Error creating subject:', error);
        if (error.response) {
            console.error('Response data:', error.response.data);
            console.error('Response status:', error.response.status);
        }
        throw error;
    }
};

// Update subject (admin only)
export const updateSubject = async (id, subjectData) => {
    try {
        const response = await subjectAPI.put(`/${id}`, subjectData);
        return response.data;
    } catch (error) {
        console.error('Error updating subject:', error);
        throw error;
    }
};

// Delete subject (admin only)
export const deleteSubject = async (id) => {
    try {
        const response = await subjectAPI.delete(`/${id}`);
        return response.data;
    } catch (error) {
        console.error('Error deleting subject:', error);
        throw error;
    }
};

export default {
    getAllSubjects,
    getFeaturedSubjects,
    getSubjectsByCategory,
    getSubjectById,
    searchSubjects,
    createSubject,
    updateSubject,
    deleteSubject
};
